//Function for layer-tap key LT(0, kc), where kc is basic keycode
//Doesn't work if the tap requires more complex function - better write it out
//as custom variable
static bool process_tap_or_long_press_key(
  keyrecord_t* record, uint16_t long_press_keycode) {
  if (record->tap.count == 0) { //Key is being held
    if (record->event.pressed) {
      tap_code16(long_press_keycode);
    }
    return false; //skip default handling
  }
  return true;
}

bool process_record_user(uint16_t keycode, keyrecord_t *record) {
  switch (keycode) {
    case COMM_COPY:
      return process_tap_or_long_press_key(record, C(KC_C));
    case SPL:
    	if (record->event.pressed) {
        //using opposite hand modifier as same hand shift/control has 
        //been programmed to not work to prevent rollover 
        //accidental modifier trigger when typing
	      tap_code16(RCTL(KC_L));
    	  tap_code16_delay(LSFT(KC_ENT), 500);
	    }
     	return false;
	    break;
    case PIPE: 
      if (record->tap.count) {
        if(record->event.pressed) {
	        SEND_STRING("||" SS_TAP(X_LEFT));
        }
        return false;
        //if held
      } else if (record->event.pressed) {
        SEND_STRING("||");        
        return false;
      } 
      return false;
      break;
    case LT(0, PGUP_DBL):
      if (record->tap.count && record->event.pressed) {
          //if shift pressed, do double page arrow down
          if(get_mods() & MOD_BIT(KC_RSFT)) {
            unregister_mods(MOD_BIT(KC_RSFT));	
            tap_code(KC_UP);
            tap_code16(RGUI(KC_LEFT));
            tap_code(KC_UP);
            tap_code16(RGUI(KC_LEFT));
            add_mods(MOD_BIT(KC_RSFT));
            return false;
          //if no shift pressed
          } else {
            tap_code(KC_PGUP);
            return false;
          }
       return false; 
      //if held
      } else if (record->event.pressed) {
        tap_code(KC_PGUP);
        tap_code(KC_PGUP);
        tap_code16(RGUI(KC_LEFT));
        tap_code(KC_PGUP);
        tap_code(KC_PGUP);
      }
      return false;
      break;
    case PGDN_DBL:
      if (record->tap.count) {
        if (record->event.pressed) {
          //if shift pressed, do double page arrow down
          if(get_mods() & MOD_BIT(KC_RSFT)) {
            unregister_mods(MOD_BIT(KC_RSFT));	
            tap_code(KC_DOWN);
            tap_code16(RGUI(KC_LEFT));
            tap_code(KC_DOWN);
            tap_code16(RGUI(KC_LEFT));
            add_mods(MOD_BIT(KC_RSFT));
            return false;
          //if no shift pressed
          } else {
            tap_code(KC_PGDN);
            return false;
          }
        }
      //if held
      } else if (record->event.pressed) {
        tap_code(KC_PGDN);
        tap_code(KC_PGDN);
        tap_code16(RGUI(KC_LEFT));
        tap_code(KC_PGDN);
        tap_code(KC_PGDN);
      }
      return false;
      break;
    //cancel rolled modifiers of same hand. Prevents modifiers accidental
    //press e.g. when press s and t key, stops ctrl + t behaviour.
    case LSFT_T(KC_T):
      if (record->event.pressed && record->tap.count > 0) {
        if (get_mods() & MOD_BIT(KC_LCTL)) {
          unregister_mods(MOD_BIT(KC_LCTL));
          tap_code(KC_S);
          tap_code(KC_T);
          add_mods(MOD_BIT(KC_LCTL));
          return false;
        }
      }
      layer_clear();
      return true;
     	break;
    case RSFT_T(KC_N):
      if (record->event.pressed && record->tap.count > 0) {
        if (get_mods() & MOD_BIT(KC_RCTL)) {
          unregister_mods(MOD_BIT(KC_RCTL));
          tap_code(KC_E);
          tap_code(KC_N);
          add_mods(MOD_BIT(KC_RCTL));
          return false;
        }
      }
      return true;
    	break;
    //enter goes back baselayer if layer set
    case KC_ENT:
      if (record->event.pressed) {
        if (IS_LAYER_ON(1) 
          || IS_LAYER_ON(2) 
          || IS_LAYER_ON(3)
          || IS_LAYER_ON(4)) {
          tap_code(KC_ENT);
          layer_clear();       
          return false;
        }
      }
      return true;
      break;
    //clears all layers if access symbol layer
    case LT(3,KC_SPC):
      //when key held d
      if (!record->tap.count) {
        if (IS_LAYER_ON(1) 
          || IS_LAYER_ON(2) 
          || IS_LAYER_ON(4)) {
          layer_clear();       
          return true;
        }
      }
      return true;
      break;
    case LT(3,KC_BSPC):
      if (!record->tap.count) {
        if (IS_LAYER_ON(1) 
          || IS_LAYER_ON(2) 
          || IS_LAYER_ON(4)) {
          layer_clear();       
          return true;
        }
      }
      return true;
      break;
    case TO(4):
      if (record->event.pressed) {
        if (IS_LAYER_ON(1) 
          || IS_LAYER_ON(2)) {
          layer_clear();       
          return true;
        }
      }
      return true;
      break;
    //escape goes back baselayer if layer set
    case KC_ESC:
      if (record->event.pressed) {
        //if (IS_LAYER_ON(1) || IS_LAYER_ON(2) || IS_LAYER_ON(4)) {
        layer_clear();       
        return true;
      }
      return true;
      break;
    case WKSP1: 
      layer_move(0);
      if (record->tap.count) {
        if(record->event.pressed) {
          register_mods(MOD_BIT(KC_RGUI));
          tap_code(KC_1);
          unregister_mods(MOD_BIT(KC_RGUI));
        }
        return false;
      //if held
      } else if (record->event.pressed) {
        register_mods(MOD_BIT(KC_RGUI));
        tap_code(KC_3);
        unregister_mods(MOD_BIT(KC_RGUI));
      }
      return false;
      break;
    case WKSP2: 
      layer_move(0);
      if (record->tap.count) {
        if(record->event.pressed) {
          register_mods(MOD_BIT(KC_RGUI));
          tap_code(KC_2);
          unregister_mods(MOD_BIT(KC_RGUI));
        }
        return false;
      } else if (record->event.pressed) {
        register_mods(MOD_BIT(KC_RGUI));
        tap_code(KC_4);
        unregister_mods(MOD_BIT(KC_RGUI));
      }
      return false;
      break;
    case COLON: 
      if (record->tap.count) {
        if(record->event.pressed) {
	        SEND_STRING(":");
        }
        return false;
        //if held fg + enter
      } else if (record->event.pressed) {
        SEND_STRING("fg");        
        tap_code(KC_ENT);
        return false;
      } 
      return false;
      break;
    case EQUAL: 
      if (record->tap.count) {
        if(record->event.pressed) {
	        SEND_STRING("=");
        }
        return false;
        //if held ctrl + z
      } else if (record->event.pressed) {
        register_mods(MOD_BIT(KC_RCTL));
        tap_code(KC_Z);
        unregister_mods(MOD_BIT(KC_RCTL));
        return false;
      } 
      return false;
      break;
    //macro for brackets
    case PAR: 
      if (record->tap.count) {
        if(record->event.pressed) {
	        SEND_STRING("()" SS_TAP(X_LEFT));
        }
        return false;
        //if held
      } else if (record->event.pressed) {
        SEND_STRING("()");        
        return false;
      } 
      return false;
      break;
    case CUR:
      if (record->tap.count) {
        if(record->event.pressed) {
	        SEND_STRING("{}" SS_TAP(X_LEFT));
        }
        return false;
        //if held
      } else if (record->event.pressed) {
        SEND_STRING("{}");        
        return false;
      } 
      return false;
      break;
    case SQU: 
      if (record->tap.count) {
        if(record->event.pressed) {
	        SEND_STRING("[]" SS_TAP(X_LEFT));
        }
        return false;
        //if held
      } else if (record->event.pressed) {
        SEND_STRING("[]");        
        return false;
      } 
      return false;
      break;
    //below needs to be added to combos to use right pinky keys
    case QUO: 
      if (record->tap.count) {
        if(record->event.pressed) {
	        SEND_STRING("''" SS_TAP(X_LEFT));
        }
        return false;
        //if held
      } else if (record->event.pressed) {
        SEND_STRING("''");        
        return false;
      } 
      return false;
      break;
    case DBLQUO: 
      if (record->tap.count) {
        if(record->event.pressed) {
	        SEND_STRING("\"\"" SS_TAP(X_LEFT));
        }
        return false;
        //if held
      } else if (record->event.pressed) {
        SEND_STRING("\"\"");        
        return false;
      } 
      return false;
      break;
    case CAPG: 
   	  if(record->event.pressed) {
        register_mods(MOD_BIT(KC_RSFT));
        tap_code(KC_G);
        layer_clear();
        unregister_mods(MOD_BIT(KC_RSFT));
        return false;
  	  } 
      return true;
	    break;
      /*
    case NEW_TAB: 
   	  if(record->event.pressed) {
        layer_clear();
        register_mods(MOD_BIT(KC_RCTL));
        tap_code(KC_T);
        unregister_mods(MOD_BIT(KC_RCTL));
        return false;
  	  } 
	    break;
      */
    case CLOSE_TAB: 
   	  if(record->event.pressed) {
        register_mods(MOD_BIT(KC_RCTL));
        tap_code(KC_W);
        unregister_mods(MOD_BIT(KC_RCTL));
        return false;
  	  } 
	    break;
    case SWITCH_TAB: 
   	  if(record->event.pressed) {
        register_mods(MOD_BIT(KC_RCTL));
        tap_code(KC_TAB);
        unregister_mods(MOD_BIT(KC_RCTL));
        return false;
  	  } 
	    break;
    case PREV_TAB: 
   	  if(record->event.pressed) {
        register_mods(MOD_BIT(KC_RCTL));
        register_mods(MOD_BIT(KC_RSFT));
        tap_code(KC_TAB);
        unregister_mods(MOD_BIT(KC_RCTL));
        unregister_mods(MOD_BIT(KC_RSFT));
        return false;
  	  } 
	    break;
    case ADD_BAR: 
   	  if(record->event.pressed) {
        layer_clear();
        SEND_STRING(SS_LCTL("l"));
        return false;
  	  } 
	    break;
    case BASE_F:
      if(record->event.pressed) {
        layer_clear();
        tap_code(KC_F);
        return false;
      }
      return true;
      break;
    case RARROW: 
   	  if(record->event.pressed) {
        tap_code(KC_RGHT);
        return false;
  	  } 
      return true;
	    break;
    case LARROW1: 
   	  if(record->tap.count && record->event.pressed) {
        tap_code(KC_LEFT);
        return false;
  	  } 
      else if (record->event.pressed) {
        register_mods(MOD_BIT(KC_LALT));
        tap_code(KC_LEFT);
        unregister_mods(MOD_BIT(KC_LALT));
        return false;
      }
	    break;
  }
  return true;
};


